<script setup lang="ts">
import { onMounted, onUnmounted, ref, watch } from 'vue'
import * as echarts from 'echarts'
import type { JobSkill } from '@/types/job'

const props = defineProps<{
  skills: JobSkill[]
}>()

const chartRef = ref<HTMLDivElement | null>(null)
let chartInstance: echarts.ECharts | null = null

function renderChart() {
  if (!chartRef.value) return

  if (!chartInstance) {
    chartInstance = echarts.init(chartRef.value)
  }

  const indicators = props.skills.map((skill) => ({
    name: skill.name,
    max: 5,
  }))
  const values = props.skills.map((skill) => skill.level)

  chartInstance.setOption({
    tooltip: {
      trigger: 'item',
      backgroundColor: 'rgba(255, 255, 255, 0.95)',
      borderColor: 'rgba(148, 163, 184, 0.3)',
      textStyle: { color: '#334155' },
    },
    radar: {
      indicator: indicators,
      shape: 'polygon',
      splitNumber: 5,
      axisName: {
        color: '#334155',
        fontSize: 12,
      },
      splitLine: {
        lineStyle: {
          color: 'rgba(148, 163, 184, 0.25)',
        },
      },
      splitArea: {
        areaStyle: {
          color: ['rgba(14, 165, 233, 0.04)', 'rgba(14, 165, 233, 0.08)'],
        },
      },
      axisLine: {
        lineStyle: {
          color: 'rgba(148, 163, 184, 0.3)',
        },
      },
    },
    series: [
      {
        type: 'radar',
        data: [
          {
            value: values,
            name: '技能要求',
            areaStyle: {
              color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [
                { offset: 0, color: 'rgba(56, 189, 248, 0.4)' },
                { offset: 1, color: 'rgba(56, 189, 248, 0.05)' },
              ]),
            },
            lineStyle: {
              color: '#38bdf8',
              width: 2,
            },
            itemStyle: {
              color: '#38bdf8',
            },
          },
        ],
      },
    ],
  })
}

onMounted(() => {
  renderChart()
  window.addEventListener('resize', () => chartInstance?.resize())
})

onUnmounted(() => {
  chartInstance?.dispose()
  window.removeEventListener('resize', () => chartInstance?.resize())
})

watch(() => props.skills, renderChart, { deep: true })
</script>

<template>
  <div
    ref="chartRef"
    class="h-72 w-full"
  />
</template>
